package org.apache.commons.csv;

import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

public class CSVParserTest {

    private CSVParser parser;

    @Mock
    private Lexer lexerMock;

    @BeforeEach
    public void setup() throws Exception {
        MockitoAnnotations.openMocks(this);

        // Create a CSVFormat mock or a real instance depending on constructor needs
        CSVFormat format = CSVFormat.DEFAULT;

        // Use a minimal Reader
        Reader reader = new StringReader("header1,header2\nvalue1,value2\nvalue3,value4");

        // Instantiate CSVParser with the Reader and format
        parser = new CSVParser(reader, format);

        // Use reflection to inject the lexer mock to control lexer behavior in getRecords(T)
        var lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);

        // Use reflection to inject headerMap if needed
        var headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);
        headerMapField.set(parser, Map.of("header1", 0, "header2", 1));

        // Reset recordNumber to 0
        var recordNumberField = CSVParser.class.getDeclaredField("recordNumber");
        recordNumberField.setAccessible(true);
        recordNumberField.setLong(parser, 0L);
    }

    @Test
    public void testGetRecords_returnsList() throws Exception {
        // Prepare a spy list to pass to private getRecords(T)
        List<CSVRecord> records = new ArrayList<>();

        // Prepare to invoke private getRecords(T) via reflection
        Method getRecordsTMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
        getRecordsTMethod.setAccessible(true);

        // Mock lexer behavior for nextRecord calls inside getRecords(T)
        // We simulate two records then a NoSuchElementException to end iteration

        // Prepare CSVRecord mocks
        CSVRecord record1 = mock(CSVRecord.class);
        CSVRecord record2 = mock(CSVRecord.class);

        // Spy parser to mock nextRecord method
        CSVParser spyParser = spy(parser);

        // Setup nextRecord to return two records then throw NoSuchElementException
        doReturn(record1)
            .doReturn(record2)
            .doThrow(new java.util.NoSuchElementException())
            .when(spyParser).nextRecord();

        // Use reflection to invoke private getRecords(T) on the spy
        @SuppressWarnings("unchecked")
        List<CSVRecord> result = (List<CSVRecord>) getRecordsTMethod.invoke(spyParser, records);

        // Verify the returned list contains the two mocked records
        assertEquals(2, result.size());
        assertSame(record1, result.get(0));
        assertSame(record2, result.get(1));
        // Verify the passed list is the same instance as returned
        assertSame(records, result);
    }

    @Test
    public void testGetRecords_callsPrivateGetRecordsT() throws IOException {
        // Spy parser to mock private getRecords(T) method call
        CSVParser spyParser = spy(parser);

        // Prepare a list to be returned by private getRecords(T)
        List<CSVRecord> mockList = new ArrayList<>();

        try {
            Method getRecordsTMethod = CSVParser.class.getDeclaredMethod("getRecords", List.class);
            getRecordsTMethod.setAccessible(true);

            // Mock private getRecords(T) method to return mockList
            doReturn(mockList).when(spyParser).getRecords(any());

            // Call public getRecords()
            List<CSVRecord> result = spyParser.getRecords();

            // Verify the returned list is the mockList
            assertSame(mockList, result);

            // Verify private getRecords(T) was called once with any List
            verify(spyParser, times(1)).getRecords(any());
        } catch (Exception e) {
            fail("Reflection exception: " + e.getMessage());
        }
    }
}
